import React, { useState } from 'react';
import { clsx } from 'clsx';
import { useScrollReveal } from '../hooks';
import { FAQ_ITEMS } from '../utils';
import { SectionHeader, Icon } from './ui';

const FAQItem = ({ item, isOpen, onClick }) => (
  <div className="border-b border-primary/[0.08]">
    <button
      className="w-full flex items-center justify-between gap-8 py-8 bg-transparent border-none cursor-pointer text-left font-sans text-lg font-medium text-primary transition-colors duration-300 hover:text-gold-dark"
      onClick={onClick}
    >
      <span>{item.question}</span>
      <div
        className={clsx(
          'w-9 h-9 flex items-center justify-center bg-cream rounded-full shrink-0 transition-all duration-500 ease-out-expo',
          isOpen && 'bg-gold rotate-45'
        )}
      >
        <Icon
          name="plus"
          size={16}
          className={clsx(
            'text-charcoal transition-colors duration-300',
            isOpen && 'text-primary'
          )}
        />
      </div>
    </button>
    <div
      className={clsx(
        'overflow-hidden transition-all duration-500 ease-out-expo',
        isOpen ? 'max-h-[300px]' : 'max-h-0'
      )}
    >
      <p
        className={clsx(
          'pb-8 text-warm-gray leading-relaxed transition-all duration-500 ease-out-expo',
          isOpen ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-2.5'
        )}
      >
        {item.answer}
      </p>
    </div>
  </div>
);

const FAQ = () => {
  const [openIndex, setOpenIndex] = useState(null);
  const [ref, isVisible] = useScrollReveal();

  const handleToggle = (index) => {
    setOpenIndex(openIndex === index ? null : index);
  };

  return (
    <section className="section" id="faq">
      <div className="container">
        <SectionHeader
          number="04"
          title="Common"
          titleHighlight="Questions"
          description="Everything you need to know about our secure will storage service."
        />

        <div
          ref={ref}
          className={clsx(
            'max-w-[800px] mx-auto opacity-0 translate-y-10 transition-all duration-700 ease-out-expo',
            isVisible && 'opacity-100 translate-y-0'
          )}
        >
          {FAQ_ITEMS.map((item, index) => (
            <FAQItem
              key={index}
              item={item}
              isOpen={openIndex === index}
              onClick={() => handleToggle(index)}
            />
          ))}
        </div>
      </div>
    </section>
  );
};

export default FAQ;
